import React, { useState, useEffect } from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';
import { useNavigate, Link } from 'react-router-dom';
import PriceTrendChart from '../components/PriceTrendChart';
import { fetchLiveMetalsPrices, MetalsData } from '../services/metalsApi';
import { yfinanceService, StockData } from '../services/yfinanceService';
import { getStaticHistoricalData } from '../services/staticHistoricalData';

const HomeContainer = styled.div`
  max-width: 1400px;
  margin: 0 auto;
  padding: 2rem 0;
`;

const PageTitle = styled(motion.div)`
  margin-bottom: 5rem;
  text-align: center;

  h1 {
    font-size: 5rem;
    font-weight: 950;
    letter-spacing: -4px;
    margin-bottom: 1rem;
    background: linear-gradient(135deg, #00f2fe 0%, #4facfe 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    text-transform: uppercase;
    line-height: 1;
  }

  p {
    color: ${props => props.theme.colors.textSecondary};
    font-size: 1.2rem;
    max-width: 700px;
    margin: 0 auto;
    letter-spacing: 1px;
    font-weight: 500;
  }

  @media (max-width: 768px) {
    h1 { font-size: 3.5rem; letter-spacing: -2px; }
  }
`;

const MarketGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 2rem;
  margin-bottom: 5rem;

  @media (max-width: 1024px) {
    grid-template-columns: repeat(2, 1fr);
  }

  @media (max-width: 640px) {
    grid-template-columns: 1fr;
  }
`;

const MarketItem = styled(motion.div)<{ positive: boolean }>`
  background: rgba(15, 15, 20, 0.4);
  backdrop-filter: blur(24px);
  padding: 2.5rem;
  border-radius: 40px;
  border: 1px solid rgba(255, 255, 255, 0.05);
  position: relative;
  overflow: hidden;
  transition: ${props => props.theme.transitions.default};

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: radial-gradient(circle at 50% 0%, ${props => props.positive ? 'rgba(16, 185, 129, 0.1)' : 'rgba(239, 68, 68, 0.1)'}, transparent 70%);
    opacity: 0;
    transition: opacity 0.5s ease;
  }

  &:hover {
    border-color: ${props => props.positive ? 'rgba(16, 185, 129, 0.3)' : 'rgba(239, 68, 68, 0.3)'};
    transform: translateY(-10px);
    box-shadow: 0 20px 40px -10px rgba(0, 0, 0, 0.5);

    &::before {
      opacity: 1;
    }
  }

  .label {
    font-size: 0.75rem;
    color: ${props => props.theme.colors.textSecondary};
    margin-bottom: 1.5rem;
    text-transform: uppercase;
    letter-spacing: 2px;
    font-weight: 800;
  }

  .price {
    font-size: 2.2rem;
    font-weight: 900;
    margin-bottom: 1rem;
    font-family: 'JetBrains Mono', monospace;
    letter-spacing: -1px;
    color: ${props => props.theme.colors.textPrimary};
  }

  .change {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    font-size: 0.95rem;
    font-weight: 800;
    padding: 0.4rem 1rem;
    border-radius: 100px;
    background: ${props => props.positive ? 'rgba(16, 185, 129, 0.1)' : 'rgba(239, 68, 68, 0.1)'};
    color: ${props => props.positive ? '#10b981' : '#ef4444'};
    border: 1px solid ${props => props.positive ? 'rgba(16, 185, 129, 0.2)' : 'rgba(239, 68, 68, 0.2)'};
  }
`;

const HeroSection = styled(motion.section)`
  display: grid;
  grid-template-columns: 1.8fr 1fr;
  gap: 3rem;
  margin-bottom: 6rem;

  @media (max-width: 1024px) {
    grid-template-columns: 1fr;
  }
`;

const GlassCard = styled(motion.div)`
  background: rgba(15, 15, 20, 0.4);
  backdrop-filter: blur(24px);
  border-radius: 48px;
  padding: 3.5rem;
  border: 1px solid rgba(255, 255, 255, 0.05);
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
  position: relative;
  overflow: hidden;

  &::after {
    content: '';
    position: absolute;
    inset: 0;
    border-radius: 48px;
    padding: 1px;
    background: linear-gradient(135deg, rgba(255, 255, 255, 0.1), transparent, rgba(255, 255, 255, 0.05));
    -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
    -webkit-mask-composite: xor;
